#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=2005;
int t,mxp,w,ap,bp,as,bs,dp[N][N];
deque<int> dq;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>t>>mxp>>w;
	memset(dp,128,sizeof(dp));
	for(int i=1;i<=t;i++)
	{
		cin>>ap>>bp>>as>>bs;
		for(int j=0;j<=mxp;j++)
		{
			if(j<=as) dp[i][j]=max(dp[i-1][j],(-j)*ap);
			else dp[i][j]=dp[i-1][j];
//			cout<<i<<" "<<j<<" : "<<dp[i][j]<<"\n";
		}
		if(i<=w) continue;
		dq.clear();
		for(int j=mxp;j>=0;j--)
		{
			while(!dq.empty()&&dq.front()>j+bs) dq.pop_front();
			while(!dq.empty()&&dp[i-w-1][j]+j*bp>=dp[i-w-1][dq.back()]+dq.back()*bp) dq.pop_back();
			dq.push_back(j);
			if(!dq.empty()) dp[i][j]=max(dp[i][j],dp[i-w-1][dq.front()]+dq.front()*bp-j*bp);
		}
		dq.clear();
		for(int j=0;j<=mxp;j++)
		{
			while(!dq.empty()&&dq.front()<j-as) dq.pop_front();
			while(!dq.empty()&&dp[i-w-1][j]+j*ap>=dp[i-w-1][dq.back()]+dq.back()*ap) dq.pop_back();
			dq.push_back(j);
			if(!dq.empty()) dp[i][j]=max(dp[i][j],dp[i-w-1][dq.front()]+dq.front()*ap-j*ap);
		}
	}
	int ans=0;
	for(int i=0;i<=mxp;i++)
	{
		ans=max(ans,dp[t][i]);
	}
	cout<<ans;
	return 0;
}
